# 5. Verifica se as notas ficam entre 0 e 10
query = """
with notas as (

    select 'disciplina_1' as disciplina, disciplina_1 as nota
    from `desafio-cientista-dados.brutos_rmi.avaliacao`

    union all

    select 'disciplina_2' as disciplina, disciplina_2 as nota
    from `desafio-cientista-dados.brutos_rmi.avaliacao`

    union all

    select 'disciplina_3' as disciplina, disciplina_3 as nota
    from `desafio-cientista-dados.brutos_rmi.avaliacao`

    union all

    select 'disciplina_4' as disciplina, disciplina_4 as nota
    from `desafio-cientista-dados.brutos_rmi.avaliacao`

)

select
    disciplina,
    count(*) as total_linhas,
    countif(nota is null) as qtd_nulos,
    min(nota) as nota_minima,
    max(nota) as nota_maxima,
    countif(nota < 0) as qtd_menor_que_zero,
    countif(nota > 10) as qtd_maior_que_dez
from notas
group by 1
order by 1
"""

display(client.query(query).to_dataframe())

